function handleMapResult(
  keyResult: ParsePayload,
  valueResult: ParsePayload,
  final: ParsePayload<Map<unknown, unknown>>,
  key: unknown,
  input: Map<any, any>,
  inst: $ZodMap,
  ctx?: ParseContext | undefined
): void {
  if (keyResult.issues.length) {
    if (util.propertyKeyTypes.has(typeof key)) {
      final.issues.push(...util.prefixIssues(key as PropertyKey, keyResult.issues));
    } else {
      final.issues.push({
        code: "invalid_key",

        origin: "map",
        input,
        inst,
        issues: keyResult.issues.map((iss) => util.finalizeIssue(iss, ctx, core.config())),
      });
    }
  }
  if (valueResult.issues.length) {
    if (util.propertyKeyTypes.has(typeof key)) {
      final.issues.push(...util.prefixIssues(key as PropertyKey, valueResult.issues));
    } else {
      final.issues.push({
        origin: "map",
        code: "invalid_element",

        input,
        inst,
        key: key,
        issues: valueResult.issues.map((iss) => util.finalizeIssue(iss, ctx, core.config())),
      });
    }
  }
  final.value.set(keyResult.value, valueResult.value);
}

export function required(
  Class: SchemaClass<schemas.$ZodNonOptional>,
  schema: schemas.$ZodObject,
  mask: object | undefined
): any {
  const def = mergeDefs(schema._zod.def, {
    get shape() {
      const oldShape = schema._zod.def.shape;
      const shape: Writeable<schemas.$ZodShape> = { ...oldShape };

      if (mask) {
        for (const key in mask) {
          if (!(key in shape)) {
            throw new Error(`Unrecognized key: "${key}"`);
          }
          if (!(mask as any)[key]) continue;
          // overwrite with non-optional
          shape[key] = new Class({
            type: "nonoptional",
            innerType: oldShape[key]!,
          });
        }
      } else {
        for (const key in oldShape) {
          // overwrite with non-optional
          shape[key] = new Class({
            type: "nonoptional",
            innerType: oldShape[key]!,
          });
        }
      }

      assignProp(this, "shape", shape); // self-caching
      return shape;
    },
  });

  return clone(schema, def) as any;
}

import { useCallback, useEffect, useRef } from 'react';

export function useEventListener<K extends keyof HTMLElementEventMap, T extends HTMLElement = any>(
  type: K,
  listener: (this: T, ev: HTMLElementEventMap[K]) => any,
  options?: boolean | AddEventListenerOptions
): React.RefCallback<T | null> {
  const previousListener = useRef<Function | null>(null);
  const previousNode = useRef<T | null>(null);

  const callbackRef: React.RefCallback<T | null> = useCallback(
    (node) => {
      if (!node) {
        return;
      }

      if (previousNode.current && previousListener.current) {
        previousNode.current.removeEventListener(type, previousListener.current as any, options);
      }

      node.addEventListener(type, listener as any, options);
      previousNode.current = node;
      previousListener.current = listener;
    },
    [type, listener, options]
  );

  useEffect(
    () => () => {
      if (previousNode.current && previousListener.current) {
        previousNode.current.removeEventListener(type, previousListener.current as any, options);
      }
    },
    [type, options]
  );

  return callbackRef;
}

import { useCallback, useRef, useState } from 'react';

export interface UseIntersectionReturnValue<T> {
  ref: React.RefCallback<T | null>;
  entry: IntersectionObserverEntry | null;
}

export function useIntersection<T extends HTMLElement = any>(
  options?: IntersectionObserverInit
): UseIntersectionReturnValue<T> {
  const [entry, setEntry] = useState<IntersectionObserverEntry | null>(null);

  const observer = useRef<IntersectionObserver | null>(null);

  const ref: React.RefCallback<T | null> = useCallback(
    (element) => {
      if (observer.current) {
        observer.current.disconnect();
        observer.current = null;
      }

      if (element === null) {
        setEntry(null);
        return;
      }

      observer.current = new IntersectionObserver(([_entry]) => {
        setEntry(_entry);
      }, options);

      observer.current.observe(element);
    },
    [options?.rootMargin, options?.root, options?.threshold]
  );

  return { ref, entry };
}

import { useCallback, useEffect, useRef } from 'react';
import { useCallbackRef } from '../utils';

export interface UseTimeoutOptions {
  autoInvoke: boolean;
}

export interface UseTimeoutReturnValue {
  start: (...args: any[]) => void;
  clear: () => void;
}

export function useTimeout(
  callback: (...args: any[]) => void,
  delay: number,
  options: UseTimeoutOptions = { autoInvoke: false }
): UseTimeoutReturnValue {
  const timeoutRef = useRef<number | null>(null);
  const handleCallback = useCallbackRef(callback);

  const start = useCallback(
    (...args: any[]) => {
      if (!timeoutRef.current) {
        timeoutRef.current = window.setTimeout(() => {
          handleCallback(...args);
          timeoutRef.current = null;
        }, delay);
      }
    },
    [delay]
  );

  const clear = useCallback(() => {
    if (timeoutRef.current) {
      window.clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
  }, []);

  useEffect(() => {
    if (options.autoInvoke) {
      start();
    }

    return clear;
  }, [clear, start]);

  return { start, clear };
}

export class CDPSession extends ChannelOwner<channels.CDPSessionChannel> implements api.CDPSession {
  static from(cdpSession: channels.CDPSessionChannel): CDPSession {
    return (cdpSession as any)._object;
  }

  constructor(parent: ChannelOwner, type: string, guid: string, initializer: channels.CDPSessionInitializer) {
    super(parent, type, guid, initializer);

    this._channel.on('event', event => {
      this.emit(event.method, event.params);
      this.emit('event', event);
    });

    this._channel.on('close', () => {
      this.emit('close', this);
    });

    this.on = super.on;
    this.addListener = super.addListener;
    this.off = super.removeListener;
    this.removeListener = super.removeListener;
    this.once = super.once;
  }

  async send<T extends keyof Protocol.CommandParameters>(
    method: T,
    params?: Protocol.CommandParameters[T]
  ): Promise<Protocol.CommandReturnValues[T]> {
    const result = await this._channel.send({ method, params });
    return result.result as Protocol.CommandReturnValues[T];
  }

  async detach() {
    return await this._channel.detach();
  }
}

constructor(@Optional() protected readonly options?: ParseUUIDPipeOptions) {
  options = options || {};
  const {
    exceptionFactory,
    errorHttpStatusCode = HttpStatus.BAD_REQUEST,
    version,
  } = options;

  this.version = version;
  this.exceptionFactory =
    exceptionFactory ||
    (error => new HttpErrorByCode[errorHttpStatusCode](error));
}

async transform(value: string, metadata: ArgumentMetadata): Promise<string> {
  if (isNil(value) && this.options?.optional) {
    return value;
  }
  if (!this.isUUID(value, this.version)) {
    throw this.exceptionFactory(
      `Validation failed (uuid${
        this.version ? ` v ${this.version}` : ''
      } is expected)`,
    );
  }
  return value;
}

protected isUUID(str: unknown, version = 'all') {
  if (!isString(str)) {
    throw this.exceptionFactory('The value passed as UUID is not a string');
  }
  const pattern = ParseUUIDPipe.uuidRegExps[version];
  return pattern?.test(str);
}

export function UseInterceptors(
  ...interceptors: (NestInterceptor | Function)[]
): MethodDecorator & ClassDecorator {
  return (
    target: any,
    key?: string | symbol,
    descriptor?: TypedPropertyDescriptor<any>,
  ) => {
    const isInterceptorValid = <T extends Function | Record<string, any>>(
      interceptor: T,
    ) =>
      interceptor &&
      (isFunction(interceptor) || isFunction(interceptor.intercept));

    if (descriptor) {
      validateEach(
        target.constructor,
        interceptors,
        isInterceptorValid,
        '@UseInterceptors',
        'interceptor',
      );
      extendArrayMetadata(
        INTERCEPTORS_METADATA,
        interceptors,
        descriptor.value,
      );
      return descriptor;
    }
    validateEach(
      target,
      interceptors,
      isInterceptorValid,
      '@UseInterceptors',
      'interceptor',
    );
    extendArrayMetadata(INTERCEPTORS_METADATA, interceptors, target);
    return target;
  };
}

export const UseFilters = (...filters: (ExceptionFilter | Function)[]) =>
  addExceptionFiltersMetadata(...filters);

function addExceptionFiltersMetadata(
  ...filters: (Function | ExceptionFilter)[]
): MethodDecorator & ClassDecorator {
  return (
    target: any,
    key?: string | symbol,
    descriptor?: TypedPropertyDescriptor<any>,
  ) => {
    const isFilterValid = <T extends Function | Record<string, any>>(
      filter: T,
    ) => filter && (isFunction(filter) || isFunction(filter.catch));

    if (descriptor) {
      validateEach(
        target.constructor,
        filters,
        isFilterValid,
        '@UseFilters',
        'filter',
      );
      extendArrayMetadata(
        EXCEPTION_FILTERS_METADATA,
        filters,
        descriptor.value,
      );
      return descriptor;
    }
    validateEach(target, filters, isFilterValid, '@UseFilters', 'filter');
    extendArrayMetadata(EXCEPTION_FILTERS_METADATA, filters, target);
    return target;
  };
}

type JsonStorageOptions = {
  reviver?: (key: string, value: unknown) => unknown
  replacer?: (key: string, value: unknown) => unknown
}

export function createJSONStorage<S, R = unknown>(
  getStorage: () => StateStorage<R>,
  options?: JsonStorageOptions,
): PersistStorage<S, unknown> | undefined {
  let storage: StateStorage<R> | undefined
  try {
    storage = getStorage()
  } catch {
    // prevent error if the storage is not defined (e.g. when server side rendering a page)
    return
  }
  const persistStorage: PersistStorage<S, R> = {
    getItem: (name) => {
      const parse = (str: string | null) => {
        if (str === null) {
          return null
        }
        return JSON.parse(str, options?.reviver) as StorageValue<S>
      }
      const str = storage.getItem(name) ?? null
      if (str instanceof Promise) {
        return str.then(parse)
      }
      return parse(str)
    },
    setItem: (name, newValue) =>
      storage.setItem(name, JSON.stringify(newValue, options?.replacer)),
    removeItem: (name) => storage.removeItem(name),
  }
  return persistStorage
}

export const getAnonymousProjectId = () => {
  if (anonymousProjectId) {
    return anonymousProjectId;
  }

  try {
    const projectRootPath = relative(getProjectRoot(), process.cwd());

    const result = executeCommandSync({
      command: 'git',
      args: ['config', '--get', 'remote.origin.url'],
      timeout: 1000,
    });

    anonymousProjectId = oneWayHash(unhashedProjectId(result, projectRootPath));
  } catch (_) {
    //
  }

  return anonymousProjectId;
};

export const getProjectSince = () => {
  try {
    if (getProjectSinceResult) {
      return getProjectSinceResult;
    }

    const dateBuffer = executeCommandSync({
      command: 'git',
      args: ['log', '--reverse', '--format=%cd', '--date=iso'],
      timeout: 1000,
    });

    const firstLine = String(dateBuffer).trim().split('\n')[0];

    const date = new Date(firstLine);

    if (Number.isNaN(date.getTime())) {
      return undefined;
    }

    getProjectSinceResult = date;
    return date;
  } catch (_) {
    //
  }

  return undefined;
};

export const getPackageManagerInfo = async () => {
  const packageManagerType = await detect({ cwd: getProjectRoot() });

  if (!packageManagerType) {
    return undefined;
  }

  // TODO: Evaluate if this is correct after removing pnp compatibility code in SB11
  let nodeLinker: 'node_modules' | 'pnp' | 'pnpm' | 'isolated' | 'hoisted' = 'node_modules';

  if (packageManagerType.name === 'yarn') {
    try {
      const { stdout } = await execaCommand('yarn config get nodeLinker', {
        cwd: getProjectRoot(),
      });
      nodeLinker = stdout.trim() as 'node_modules' | 'pnp' | 'pnpm';
    } catch (e) {}
  }

  if (packageManagerType.name === 'pnpm') {
    try {
      const { stdout } = await execaCommand('pnpm config get nodeLinker', {
        cwd: getProjectRoot(),
      });
      nodeLinker = (stdout.trim() as 'isolated' | 'hoisted' | 'pnpm') ?? 'isolated';
    } catch (e) {}
  }

  return {
    type: packageManagerType.name,
    version: packageManagerType.version,
    agent: packageManagerType.agent,
    nodeLinker,
  };
};

export function shouldThrowError<T extends (...args: Array<any>) => boolean>(
  throwOnError: boolean | T | undefined,
  params: Parameters<T>,
): boolean {
  // Allow throwOnError function to override throwing behavior on a per-error basis
  if (typeof throwOnError === 'function') {
    return throwOnError(...params)
  }

  return !!throwOnError
}

export function addConsumeAwareSignal<T>(
  object: T,
  getSignal: () => AbortSignal,
  onCancelled: VoidFunction,
): T & { signal: AbortSignal } {
  let consumed = false
  let signal: AbortSignal | undefined

  Object.defineProperty(object, 'signal', {
    enumerable: true,
    get: () => {
      signal ??= getSignal()
      if (consumed) {
        return signal
      }

      consumed = true
      if (signal.aborted) {
        onCancelled()
      } else {
        signal.addEventListener('abort', onCancelled, { once: true })
      }

      return signal
    },
  })

  return object as T & { signal: AbortSignal }
}

removeQueries<TTaggedQueryKey extends QueryKey = QueryKey>(
  filters?: QueryFilters<TTaggedQueryKey>,
): void {
  const queryCache = this.#queryCache
  notifyManager.batch(() => {
    queryCache.findAll(filters).forEach((query) => {
      queryCache.remove(query)
    })
  })
}

resetQueries<TTaggedQueryKey extends QueryKey = QueryKey>(
  filters?: QueryFilters<TTaggedQueryKey>,
  options?: ResetOptions,
): Promise<void> {
  const queryCache = this.#queryCache

  return notifyManager.batch(() => {
    queryCache.findAll(filters).forEach((query) => {
      query.reset()
    })
    return this.refetchQueries(
      {
        type: 'active',
        ...filters,
      },
      options,
    )
  })
}

cancelQueries<TTaggedQueryKey extends QueryKey = QueryKey>(
  filters?: QueryFilters<TTaggedQueryKey>,
  cancelOptions: CancelOptions = {},
): Promise<void> {
  const defaultedCancelOptions = { revert: true, ...cancelOptions }

  const promises = notifyManager.batch(() =>
    this.#queryCache
      .findAll(filters)
      .map((query) => query.cancel(defaultedCancelOptions)),
  )

  return Promise.all(promises).then(noop).catch(noop)
}

export function applySourcemapIgnoreList(
  map: ExistingRawSourceMap,
  sourcemapPath: string,
  sourcemapIgnoreList: (sourcePath: string, sourcemapPath: string) => boolean,
  logger?: Logger,
): void {
  let { x_google_ignoreList } = map
  if (x_google_ignoreList === undefined) {
    x_google_ignoreList = []
  }
  if (map.sources) {
    for (
      let sourcesIndex = 0;
      sourcesIndex < map.sources.length;
      ++sourcesIndex
    ) {
      const sourcePath = map.sources[sourcesIndex]
      if (!sourcePath) continue

      const ignoreList = sourcemapIgnoreList(
        path.isAbsolute(sourcePath)
          ? sourcePath
          : path.resolve(path.dirname(sourcemapPath), sourcePath),
        sourcemapPath,
      )
      if (logger && typeof ignoreList !== 'boolean') {
        logger.warn('sourcemapIgnoreList function must return a boolean.')
      }

      if (ignoreList && !x_google_ignoreList.includes(sourcesIndex)) {
        x_google_ignoreList.push(sourcesIndex)
      }
    }

    if (x_google_ignoreList.length > 0) {
      if (!map.x_google_ignoreList)
        map.x_google_ignoreList = x_google_ignoreList
    }
  }
}

export function warnFutureDeprecation(
  config: ResolvedConfig,
  type: keyof FutureOptions,
  extraMessage?: string,
  stacktrace = true,
): void {
  if (
    _ignoreDeprecationWarnings ||
    !config.future ||
    config.future[type] !== 'warn'
  )
    return

  let msg = `[vite future] ${deprecationMessages[type]}`
  if (extraMessage) {
    msg += ` ${extraMessage}`
  }
  msg = colors.yellow(msg)

  const docs = `${docsURL}/changes/${deprecationCode[type].toLowerCase()}`
  msg +=
    colors.gray(`\n  ${stacktrace ? '├' : '└'}─── `) +
    colors.underline(docs) +
    '\n'

  if (stacktrace) {
    const stack = new Error().stack
    if (stack) {
      let stacks = stack
        .split('\n')
        .slice(3)
        .filter((i) => !i.includes('/node_modules/vite/dist/'))
      if (stacks.length === 0) {
        stacks.push('No stack trace found.')
      }
      stacks = stacks.map(
        (i, idx) => `  ${idx === stacks.length - 1 ? '└' : '│'} ${i.trim()}`,
      )
      msg += colors.dim(stacks.join('\n')) + '\n'
    }
  }
  config.logger.warnOnce(msg)
}

override async doUpdateDefaultViewport() {
  if (!this._options.viewport && !this._options.screen)
    return;

  const screenSize = (this._options.screen || this._options.viewport)!;
  const viewportSize = (this._options.viewport || this._options.screen)!;
  await Promise.all([
    this._browser._browserSession.send('browsingContext.setViewport', {
      viewport: {
        width: viewportSize.width,
        height: viewportSize.height
      },
      devicePixelRatio: this._options.deviceScaleFactor || 1,
      userContexts: [this._userContextId()],
    }),
    this._browser._browserSession.send('emulation.setScreenOrientationOverride', {
      screenOrientation: getScreenOrientation(!!this._options.isMobile, screenSize),
      userContexts: [this._userContextId()],
    }),
    this._browser._browserSession.send('emulation.setScreenSettingsOverride', {
      screenArea: {
        width: screenSize.width,
        height: screenSize.height,
      },
      userContexts: [this._userContextId()],
    })
  ]);
}

async resolve(
  id: string,
  importer?: string,
  options?: {
    attributes?: Record<string, string>
    custom?: CustomPluginOptions
    isEntry?: boolean
    skipSelf?: boolean
  },
): Promise<ResolvedId | null> {
  let skipCalls: readonly SkipInformation[] | undefined
  if (options?.skipSelf === false) {
    skipCalls = this._resolveSkipCalls
  } else if (this._resolveSkipCalls) {
    const skipCallsTemp = [...this._resolveSkipCalls]
    const sameCallIndex = this._resolveSkipCalls.findIndex(
      (c) =>
        c.id === id && c.importer === importer && c.plugin === this._plugin,
    )
    if (sameCallIndex !== -1) {
      skipCallsTemp[sameCallIndex] = {
        ...skipCallsTemp[sameCallIndex],
        called: true,
      }
    } else {
      skipCallsTemp.push({ id, importer, plugin: this._plugin })
    }
    skipCalls = skipCallsTemp
  } else {
    skipCalls = [{ id, importer, plugin: this._plugin }]
  }

  let out = await this._container.resolveId(id, importer, {
    attributes: options?.attributes,
    custom: options?.custom,
    isEntry: !!options?.isEntry,
    skip: this._resolveSkips,
    skipCalls,
    scan: this._scan,
  })
  if (typeof out === 'string') out = { id: out }
  return out as ResolvedId | null
}

function handleArrayResult(result: ParsePayload<any>, final: ParsePayload<any[]>, index: number) {
  if (result.issues.length) {
    final.issues.push(...util.prefixIssues(index, result.issues));
  }
  final.value[index] = result.value;
}

export const $ZodArray: core.$constructor<$ZodArray> = /*@__PURE__*/ core.$constructor("$ZodArray", (inst, def) => {
  $ZodType.init(inst, def);

  inst._zod.parse = (payload, ctx) => {
    const input = payload.value;

    if (!Array.isArray(input)) {
      payload.issues.push({
        expected: "array",
        code: "invalid_type",

        input,
        inst,
      });
      return payload;
    }

    payload.value = Array(input.length);
    const proms: Promise<any>[] = [];
    for (let i = 0; i < input.length; i++) {
      const item = input[i];
      const result = def.element._zod.run(
        {
          value: item,
          issues: [],
        },
        ctx
      );

      if (result instanceof Promise) {
        proms.push(result.then((result) => handleArrayResult(result, payload, i)));
      } else {
        handleArrayResult(result, payload, i);
      }
    }

    if (proms.length) {
      return Promise.all(proms).then(() => payload);
    }

    return payload; //handleArrayResultsAsync(parseResults, final);
  };
});

export async function deployToFirebase(
  deployment: Deployment,
  configPath: string,
  stagingDir: string,
) {
  if (deployment.destination == undefined) {
    console.log(`No deployment necessary for docs created from: ${deployment.branch}`);
    return;
  }

  console.log('Preparing for deployment to firebase...');

  const deployConfigPath = join(stagingDir, 'firebase.json');

  const config = JSON.parse(await readFile(configPath, {encoding: 'utf-8'})) as {
    hosting: {public: string};
  };
  config['hosting']['public'] = './browser';

  await writeFile(deployConfigPath, JSON.stringify(config, null, 2));

  firebase(
    `target:clear --config ${deployConfigPath} --project angular-dev-site hosting angular-docs`,
    stagingDir,
  );
  firebase(
    `target:apply --config ${deployConfigPath} --project angular-dev-site hosting angular-docs ${deployment.destination}`,
    stagingDir,
  );
  firebase(
    `deploy --config ${deployConfigPath} --project angular-dev-site --only hosting --non-interactive`,
    stagingDir,
  );
  firebase(
    `target:clear --config ${deployConfigPath} --project angular-dev-site hosting angular-docs`,
    stagingDir,
  );

  await rm(stagingDir, {recursive: true});
}

export function printInitializerFunctionSignatureLine(
  name: string,
  signature: FunctionSignatureMetadata,
  showTypesInSignaturePreview: boolean,
): string {
  let res = name;
  if (signature.generics.length > 0) {
    res += '<';
    for (let i = 0; i < signature.generics.length; i++) {
      const generic = signature.generics[i];
      res += generic.name;
      if (generic.default !== undefined) {
        res += ` = ${generic.default}`;
      }
      if (i < signature.generics.length - 1) {
        res += ', ';
      }
    }
    res += '>';
  }
  res += '(';
  for (let i = 0; i < signature.params.length; i++) {
    const param = signature.params[i];
    if (param.isRestParam) {
      res += '...';
    }
    res += `${param.name}${markOptional(param.isOptional)}`;
    if (showTypesInSignaturePreview) {
      res += `: ${param.type}`;
    }
    if (i < signature.params.length - 1) {
      res += ', ';
    }
  }
  res += ')';
  if (showTypesInSignaturePreview) {
    res += `: ${signature.returnType}`;
  }
  res += ';';
  return `function ${res}`;
}

function handleEndRegion(
  openRegions: string[],
  endRegion: RegExpMatchArray,
  regionMap: Record<string, Region>,
  index: number,
  countOfRegionLines: number,
) {
  if (openRegions.length === 0) {
    throw new Error('Tried to close a region when none are open');
  }
  // close down the specified region (or most recent if no name is given)
  const regionNames = getRegionNames(endRegion[1]);
  if (regionNames.length === 0) {
    regionNames.push(openRegions[openRegions.length - 1]);
  }

  for (const regionName of regionNames) {
    const region = regionMap[regionName];
    if (!region || !region.open) {
      throw new Error(`Tried to close a region, named "${regionName}", that is not open`);
    }

    // Region is closed, we can define the last line number of the region
    region.open = false;
    region.ranges[region.ranges.length - 1].to = index - countOfRegionLines;
    removeLast(openRegions, regionName);
  }
}

function linkApiEntriesTransformer(apiEntries?: ApiEntries): ShikiTransformer {
  if (apiEntries === undefined) {
    return {};
  }
  return {
    preprocess(code, options) {
      options.decorations ??= [];
      scanner.setText(code);
      let token = scanner.scan();

      while (token !== ts.SyntaxKind.EndOfFileToken) {
        if (token === ts.SyntaxKind.Identifier) {
          const symbolUrl = getSymbolUrl(scanner.getTokenText(), apiEntries);
          if (symbolUrl !== undefined) {
            options.decorations.push({
              transform: (el) => {
                el.tagName = 'a';
                el.properties['href'] = symbolUrl;
                return el;
              },
              start: scanner.getTokenStart(),
              end: scanner.getTokenEnd(),
            });
          }
        }

        token = scanner.scan();
      }

      return code;
    },
  };
}

function buildFileSystemTree(
  fileSystemTree: FileSystemTree,
  fileDirectories: string[],
  filename: FileAndContent['path'],
  fileContents: FileAndContent['content'],
): void {
  if (fileDirectories.length === 1) {
    const directory = fileDirectories[0];

    const fileNode: FileNode = {file: {contents: fileContents}};

    fileSystemTree[directory] = {
      ...fileSystemTree[directory],

      directory: {
        ...(fileSystemTree[directory]
          ? (fileSystemTree[directory] as DirectoryNode).directory
          : undefined),

        [filename]: fileNode,
      },
    };

    return;
  }

  const nextDirectory = fileDirectories.shift();
  if (!nextDirectory) return;

  if (!fileSystemTree[nextDirectory]) {
    fileSystemTree[nextDirectory] = {directory: {}};
  }

  buildFileSystemTree(
    (fileSystemTree[nextDirectory] as DirectoryNode).directory,
    fileDirectories,
    filename,
    fileContents,
  );
}

const numericValueHandler: ParserHandler = (tokens) => {
  if (typeof tokens[0] === 'number') {
    const value: NumericValue = {
      type: 'numeric',
      values: [],
    };
    let buffer = [];

    for (const token of tokens) {
      if (typeof token === 'number') {
        // Add a value to the list (with or without unit)
        if (buffer.length) {
          value.values.push((buffer.length === 1 ? [buffer[0], ''] : buffer) as [number, string]);
          buffer = [];
        }

        buffer.push(token);
      } else if (buffer.length === 1) {
        // If string, expect a numeric value (i.e. buffer.length == 1) in the buffer.
        buffer.push(token);
      } else {
        // Any other case means, the value is invalid.
        return null;
      }
    }

    // Add any remaining values in the buffer
    if (buffer.length) {
      value.values.push((buffer.length === 1 ? [buffer[0], ''] : buffer) as [number, string]);
    }

    return value;
  }

  return null;
};

const getNestedPropertiesCallback =
  (messageBus: MessageBus<Events>) => (position: DirectivePosition, propPath: string[]) => {
