  }
};

function createTableDom(data: TableCell[][]) {
  const table = document.createElement('table');
  const tbody = document.createElement('tbody');
  table.appendChild(tbody);
  for (let r = 0; r < data.length; r++) {
    const dataRow = data[r];
    const tr = document.createElement('tr');
    // Mark created DOM nodes, so that we can verify that
    // they were *not* re-created during hydration.
    (tr as any).__existing = true;
    tbody.appendChild(tr);
    const renderRow = [];
    for (let c = 0; c < dataRow.length; c++) {
      const dataCell = dataRow[c];
      const renderCell = document.createElement('td');
      // Mark created DOM nodes, so that we can verify that
      // they were *not* re-created during hydration.
      (renderCell as any).__existing = true;
      if (r % 2 === 0) {
        renderCell.style.backgroundColor = 'grey';
      }
      tr.appendChild(renderCell);
      renderRow[c] = renderCell;
      renderCell.textContent = dataCell.value;
    }
    // View container anchor
    const comment = document.createComment('');
    tr.appendChild(comment);
  }
  // View container anchor
  const comment = document.createComment('');
  tbody.appendChild(comment);
  return table;
}

export async function* takeWithGrace<T>(
  iterable: AsyncIterable<T>,
  opts: {
    count: number;
    gracePeriodMs: number;
  },
): AsyncGenerator<T> {
  await using iterator = iteratorResource(iterable);

  // declaration outside the loop for garbage collection reasons
  let result: null | IteratorResult<T> | typeof disposablePromiseTimerResult;

  using timer = timerResource(opts.gracePeriodMs);

  let count = opts.count;

  let timerPromise = new Promise<typeof disposablePromiseTimerResult>(() => {
    // never resolves
  });

  while (true) {
    result = await Unpromise.race([iterator.next(), timerPromise]);
    if (result === disposablePromiseTimerResult) {
      throwAbortError();
    }
    if (result.done) {
      return result.value;
    }
    yield result.value;
    if (--count === 0) {
      timerPromise = timer.start();
    }
    // free up reference for garbage collection
    result = null;
  }
}

export function createModuleTypeClassifier(options: ModuleTypeClassifierOptions) {
  const { patterns, basePath: _basePath } = options;
  const basePath = _basePath !== undefined ? normalizeSlashes(_basePath).replace(/\/$/, '') : undefined;

  const patternTypePairs = Object.entries(patterns ?? []).map(([_pattern, type]) => {
    const pattern = normalizeSlashes(_pattern);
    return { pattern: parsePattern(basePath!, pattern), type };
  });

  const classifications: Record<ModuleTypeOverride, ModuleTypeClassification> = {
    package: {
      moduleType: 'auto',
    },
    cjs: {
      moduleType: 'cjs',
    },
    esm: {
      moduleType: 'esm',
    },
  };
  const auto = classifications.package;

  // Passed path must be normalized!
  function classifyModuleNonCached(path: string): ModuleTypeClassification {
    const matched = matchPatterns(patternTypePairs, (_) => _.pattern, path);
    if (matched) return classifications[matched.type];
    return auto;
  }

  const classifyModule = cachedLookup(classifyModuleNonCached);

  function classifyModuleAuto(path: String) {
    return auto;
  }

  return {
    classifyModuleByModuleTypeOverrides: patternTypePairs.length ? classifyModule : classifyModuleAuto,
  };
}

export function interpolateCodeExamples(entries: DocEntry[]): void {
  for (const entry of entries) {
    entry.rawComment = replaceExample(entry.rawComment);
    entry.description = replaceExample(entry.description);

    for (const jsdocTag of entry.jsdocTags) {
      jsdocTag.comment = replaceExample(jsdocTag.comment);
    }

    if ('members' in entry) {
      const members = (entry as ClassEntry).members ?? [];
      for (const member of members) {
        member.description = replaceExample(member.description);

        for (const jsdocTag of member.jsdocTags) {
          jsdocTag.comment = replaceExample(jsdocTag.comment);
        }

        const method = member as MethodEntry;
        if (method.implementation) {
          for (const functionSignature of [method.implementation, ...(method.signatures ?? [])]) {
            functionSignature.description = replaceExample(functionSignature.description);
            functionSignature.jsdocTags.forEach((jsdocTag) => {
              jsdocTag.comment = replaceExample(jsdocTag.comment);
            });
          }
        }
      }
    }
  }
}

function getCodeTocData(members: MemberEntry[], isDeprecated: boolean): CodeTableOfContentsData {
  const initialMetadata: CodeTableOfContentsData = {
    contents: '',
    codeLineNumbersWithIdentifiers: new Map<number, string>(),
    deprecatedLineNumbers: isDeprecated ? [0] : [],
  };
  let lineNumber = 1;

  return members.reduce((acc: CodeTableOfContentsData, curr: MemberEntry, index: number) => {
    const setTocData = (entry: DocEntry | MemberEntry, content: string) => {
      acc.contents += `${INDENTED_NEW_LINE}${content}`;
      acc.codeLineNumbersWithIdentifiers.set(lineNumber, entry.name);
      if (isDeprecatedEntry(entry)) {
        acc.deprecatedLineNumbers.push(lineNumber);
      }

      lineNumber++;
    };

    if (isClassMethodEntry(curr)) {
      // class methods
      if (curr.signatures.length > 0) {
        curr.signatures.forEach((signature) => {
          setTocData(signature, getMethodCodeLine(signature, curr.memberTags));
        });
      } else {
        // Constructors, methods on interfaces, Decorators
        setTocData(curr, getMethodCodeLine(curr.implementation, curr.memberTags));
      }
    } else {
      // class props
      setTocData(curr, getCodeLine(curr));
    }
    return acc;
  }, initialMetadata);
}

function mapManifestToEntries(
  apiManifest: ApiManifest,
): Record<string, {moduleName: string; targetSymbol?: string}> {
  const duplicateEntries = new Set<string>();

  const entryToModuleMap: Record<string, {moduleName: string; targetSymbol?: string}> = {};
  for (const pkg of apiManifest) {
    for (const entry of pkg.entries) {
      if (duplicateEntries.has(entry.name)) {
        continue;
      } else if (entryToModuleMap[entry.name]) {
        delete entryToModuleMap[entry.name];
        duplicateEntries.add(entry.name);
      } else {
        const normalizedModuleName = pkg.moduleName.replace(/^@angular\//, '');

        entryToModuleMap[entry.name] = {moduleName: normalizedModuleName};

        // If there are aliases, create entries for each alias
        if (entry.aliases) {
          for (const alias of entry.aliases) {
            entryToModuleMap[alias] = {
              moduleName: normalizedModuleName,
              targetSymbol: entry.name,
            };
          }
        }
      }
    }
  }
  return entryToModuleMap;
}

tokenizer(this: TokenizerThis, src: string): DocsCardToken | undefined {
  const match = cardRule.exec(src);

  if (match) {
    const attr = match[1] ? match[1].trim() : '';
    const title = titleRule.exec(attr);
    const link = linkRule.exec(attr);
    const href = hrefRule.exec(attr);
    const imgSrc = imgSrcRule.exec(attr);
    const iconImgSrc = iconImgSrcRule.exec(attr);
    const titleInline = titleInlineRule.test(attr);

    const body = match[2].trim();

    const token: DocsCardToken = {
      type: 'docs-card',
      raw: match[0],
      title: title ? title[1] : '',
      body: body ?? '',
      href: href ? href[1] : undefined,
      link: link ? link[1] : undefined,
      imgSrc: imgSrc ? imgSrc[1] : undefined,
      iconImgSrc: iconImgSrc ? iconImgSrc[1] : undefined,
      titleInline,
      tokens: [],
    };
    this.lexer.blockTokens(token.body, token.tokens);
    return token;
  }
  return undefined;
}

async function getAnswerFiles(
  path: string,
  config: TutorialConfig,
  files: FileAndContentRecord,
): Promise<FileAndContentRecord> {
  const answerFiles: FileAndContentRecord = {};
  const answerPrefix = /answer[\\/]/;

  if (config.answerSrc) {
    assert(config.answerRootDir, `No \`answerRootDir\` specified for: ${path}`);

    const answersDir = join(path, config.answerSrc);
    const answerRootDir = join(path, config.answerRootDir);

    const answerFilePaths = await glob('**/*', {
      cwd: answersDir,
      onlyFiles: true,
      absolute: false,
    });

    for (const answerFile of answerFilePaths) {
      const absAnswerFile = join(answersDir, answerFile);
      // Relativize answer file path.
      const filePath = relative(answerRootDir, absAnswerFile);
      // We use the absolute file in order to read the content, but the key
      // needs to be a relative path within the project.
      answerFiles[filePath] = getFileContents(absAnswerFile);
    }
  } else {
    for (const file of Object.keys(files)) {
      if (answerPrefix.test(file)) {
        answerFiles[file.replace(answerPrefix, '')] = files[file];
      }
    }
  }

  return answerFiles;
}

const getLatestComponentExplorerViewCallback =
  (messageBus: MessageBus<Events>) => (query?: ComponentExplorerViewQuery) => {
    // We want to force re-indexing of the component tree.
    // Pressing the refresh button means the user saw stuck UI.

    initializeOrGetDirectiveForestHooks().indexForest();

    const forest = prepareForestForSerialization(
      initializeOrGetDirectiveForestHooks().getIndexedDirectiveForest(),
      ngDebugDependencyInjectionApiIsSupported(),
    );

    if (!query) {
      messageBus.emit('latestComponentExplorerView', [{forest}]);
      return;
    }

    const state = getLatestComponentState(
      query,
      initializeOrGetDirectiveForestHooks().getDirectiveForest(),
    );

    if (state) {
      const {directiveProperties} = state;
      messageBus.emit('latestComponentExplorerView', [{forest, properties: directiveProperties}]);
    } else {
      // if the node is not found in the tree, we assume its gone and send the tree as is.
      messageBus.emit('latestComponentExplorerView', [{forest}]);
    }
  };

const getTransferStateCallback = (messageBus: MessageBus<Events>) => () => {
  const ng = ngDebugClient();

  const forest = initializeOrGetDirectiveForestHooks().getIndexedDirectiveForest();
  if (forest.length === 0) {
    messageBus.emit('transferStateData', [null]);
    return;
  }

  const rootNode = forest[0];
  if (!rootNode || !rootNode.nativeElement) {
    messageBus.emit('transferStateData', [null]);
    return;
  }

  const injector = getInjectorFromElementNode(rootNode.nativeElement);
  if (!injector) {
    messageBus.emit('transferStateData', [null]);
    return;
  }

  const transferStateData = (ng.ɵgetTransferState?.(injector) ?? null) as Record<
    string,
    TransferStateValue
  > | null;

  if (
    transferStateData &&
    typeof transferStateData === 'object' &&
    Object.keys(transferStateData).length > 0
  ) {
    messageBus.emit('transferStateData', [transferStateData]);
  } else {
    messageBus.emit('transferStateData', [null]);
  }
};

async function getNewVersion(commits: string[]): Promise<string> {
  console.log('');
  console.log(chalk.blue('Determining new version...'));
  const currentVersion = await getCurrentVersion();
  const releaseType = commits.some((commit) => commit.startsWith('feat')) ? 'minor' : 'patch';
  const suggestedVersion = semver.inc(currentVersion, releaseType) ?? currentVersion;

  const newVersion = await input({
    message: 'Enter the new version number',
    default: suggestedVersion,
    validate: (value) => {
      if (!semver.valid(value)) {
        return chalk.red('Please enter a valid version number.');
      }

      if (semver.lte(value, currentVersion)) {
        return chalk.red(
          `Please enter a version number greater than the current version (${currentVersion}).`,
        );
      }

      return true;
    },
  });

  console.log(chalk.green(`New version set to: ${newVersion}`));

  return newVersion;
}

