function applyContainerAttributesAndClasses(el: Element, token: CodeToken) {
  // Attributes
  // String value attributes
  if (token.path) {
    el.setAttribute('path', token.path);
  }
  if (token.visibleLines) {
    el.setAttribute('visibleLines', expandRangeStringValues(token.visibleLines).toString());
  }
  if (token.header) {
    el.setAttribute('header', token.header);
  }

  // Boolean value attributes
  if (token.preview) {
    el.setAttribute('preview', 'true');
  }
  if (token.hideCode) {
    el.setAttribute('hideCode', 'true');
  }
  if (token.hideCopy) {
    el.setAttribute('hideCopy', 'true');
  }
  if (token.hideDollar) {
    el.setAttribute('hideDollar', 'true');
  }

  const language = token.language;

  if (language === 'mermaid') {
    el.setAttribute('mermaid', 'true');
  }

  // Classes
  if (language === 'shell' || language === 'bash') {
    el.classList.add('shell');
  }

  if (token.classes) {
    el.classList.add(...token.classes);
  }
}

handleTabKeypress(event: KeyboardEvent): void {
  const focusableChildren = this.getFocusableChildren();

  if (focusableChildren.length === 0) {
    return;
  }

  // Shift+tab on expanding row summary should focus on last focusable element
  // before expanding row list. Otherwise, if shift+tab is pressed on first
  // focusable child inside expanding row summary, it should focus on main
  // expanding row summary element.
  if (event.shiftKey && document.activeElement === this.mainElementRef.nativeElement) {
    event.preventDefault();
    this.expandingRow.expandingRowHost.focusOnPreviousFocusableElement();
    return;
  } else if (event.shiftKey && document.activeElement === focusableChildren[0]) {
    event.preventDefault();
    this.expandingRow.focus();
  }

  // If tab is pressed on the last focusable element inside an expanding row
  // summary, focus should be set to the next focusable element after the list
  // of expanding rows.
  if (
    !event.shiftKey &&
    document.activeElement === focusableChildren[focusableChildren.length - 1]
  ) {
    event.preventDefault();
    this.expandingRow.expandingRowHost.focusOnNextFocusableElement();
  }
}

constructor() {
  if (this.isServer) {
    return;
  }

  effect(() => {
    const foundTemplate = this.templates.find((t) => t.id === this.templateId());
    this.changeTemplate(foundTemplate ?? this.defaultTemplate);
  });

  // If using `async-await`, `this` will be captured until the function is executed
  // and completed, which can lead to a memory leak if the user navigates away from
  // the playground component to another page.
  forkJoin({
    nodeRuntimeSandbox: injectNodeRuntimeSandbox(this.environmentInjector),
    embeddedEditorComponent: import('../../editor/index').then((c) => c.EmbeddedEditor),
  })
    .pipe(
      tap(({nodeRuntimeSandbox, embeddedEditorComponent}) => {
        this.nodeRuntimeSandbox = nodeRuntimeSandbox;
        this.embeddedEditorComponent.set(embeddedEditorComponent);
      }),
      switchMap(() => this.loadTemplate(this.selectedTemplate.path)),
      takeUntilDestroyed(this.destroyRef),
    )
    .subscribe(() => {
      this.nodeRuntimeSandbox?.init();
      this.isSandboxReady.set(true);
    });
}
